INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 0.0, 4, 0.0, 4, 24, 110501, 1, 24015);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 4.0, 4, 0.0, 1, 24, 110501, 2, 24016);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 0.0, 4, 0.0, 4, 24, 110501, 3, 24017);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 5.2, 1, 0.0, 2, 24, 110501, 4, 24018);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 4.2, 5, 0.0, 6, 24, 110501, 5, 24019);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 0.0, 2, 0.0, 2, 24, 110501, 6, 24020);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 6.4, 1, 0.0, 6, 24, 110501, 7, 24021);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 0.0, 2, 0.0, 2, 24, 110501, 8, 24022);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 10.08, 6, 0.0, 3, 24, 110501, 9, 24023);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 5.0, 1, 0.0, 2, 24, 110501, 10, 24024);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES ("2030/12/17 14:59:59", "2019/07/31 12:00:00", 10021, "カオリ（サマー）", 0.0, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 0.0, 2, 0.0, 2, 24, 110501, 11, 24025);
